@RestController
@RequestMapping("/api/products")
class ProductController {

    private final ProductService productService;

    ProductController(ProductService productService) {
        this.productService = productService;
    }

    @GetMapping(produces = MediaType.APPLICATION_JSON_VALUE)
    public List<Product> searchProducts(@RequestParam("name") String name) {
        return productService.searchByName(name);
    }
}

@org.springframework.stereotype.Service
class ProductService {

    private final JdbcTemplate jdbcTemplate;

    ProductService(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    public List<Product> searchByName(String name) {
        String sql = "SELECT id, name, description, price FROM products WHERE name LIKE ?";
        String searchTerm = "%" + name + "%";

        RowMapper<Product> rowMapper = (rs, rowNum) -> new Product(
                rs.getLong("id"),
                rs.getString("name"),
                rs.getString("description"),
                rs.getBigDecimal("price")
        );

        return jdbcTemplate.query(sql, rowMapper, searchTerm);
    }
}

